""" Small utilities to time the execution time of functions
"""

import logging
import time

LOGGER = logging.getLogger(__name__)


def measure_time(function):
    """Apply this decorator to log the time a function takes to run"""

    def wrap(*args, **kwargs):
        LOGGER.info(f"Starting '{function.__name__}'")
        start_time = time.time()
        res = function(*args, **kwargs)
        LOGGER.info(
            f"Execution time of '{function.__name__}': {time.time() - start_time}"
        )
        return res

    return wrap


@measure_time
def time_func(function, *args, **kwargs):
    """Convenience function to run the function f and log its execution time"""
    return function(*args, **kwargs)
